import{_ as o,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新日誌：版本歷史 | opencode-md-table-formatter","description":"了解 opencode-md-table-formatter 的版本演進和新功能。查看 v0.1.0 特性，包括自動格式化和寬度快取等。","frontmatter":{"title":"更新日誌：版本歷史 | opencode-md-table-formatter","sidebarTitle":"版本變化一覽","subtitle":"更新日誌：版本歷史與變更記錄","description":"了解 opencode-md-table-formatter 的版本演進和新功能。查看 v0.1.0 特性，包括自動格式化和寬度快取等。","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"zh-tw/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"zh-tw/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),a={name:"zh-tw/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(n,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="更新日誌-版本歷史與變更記錄" tabindex="-1">更新日誌：版本歷史與變更記錄 <a class="header-anchor" href="#更新日誌-版本歷史與變更記錄" aria-label="Permalink to &quot;更新日誌：版本歷史與變更記錄&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">學完你能做什麼</p><ul><li>追蹤外掛的版本演進歷程</li><li>了解每個版本的新功能和修復</li><li>掌握已知限制和技術細節</li><li>了解未來可能的功能增強</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><p>這是 opencode-md-table-formatter 的<strong>初始發布版本</strong>，包含以下核心功能：</p><ul><li><strong>自動表格格式化</strong>：透過 <code>experimental.text.complete</code> 鉤子自動格式化 AI 生成的 Markdown 表格</li><li><strong>隱藏模式支援</strong>：計算寬度時正確處理隱藏的 Markdown 符號（如 <code>**</code>、<code>*</code>）</li><li><strong>巢狀 Markdown 處理</strong>：支援任意深度的巢狀 Markdown 語法，使用多遍剝離演算法</li><li><strong>程式碼區塊保護</strong>：行內程式碼（<code>`code`</code>）內的 Markdown 符號保持字面形式，不參與寬度計算</li><li><strong>對齊方式支援</strong>：支援左對齊（<code>---</code> 或 <code>:---</code>）、置中對齊（<code>:---:</code>）、右對齊（<code>---:</code>）</li><li><strong>寬度快取最佳化</strong>：快取字串顯示寬度計算結果，提升效能</li><li><strong>無效表格驗證</strong>：自動驗證表格結構，無效表格會添加錯誤註釋</li><li><strong>多字元支援</strong>：支援 Emoji、Unicode 字元、空白儲存格、超長內容</li><li><strong>靜默錯誤處理</strong>：格式化失敗不會中斷 OpenCode 工作流程</li></ul><h3 id="技術細節" tabindex="-1">技術細節 <a class="header-anchor" href="#技術細節" aria-label="Permalink to &quot;技術細節&quot;">​</a></h3><p>本版本包含約 <strong>230 行生產就緒的 TypeScript 程式碼</strong>：</p><ul><li><strong>12 個函數</strong>：職責清晰，分離良好</li><li><strong>類型安全</strong>：正確使用 <code>Hooks</code> 介面</li><li><strong>智慧快取清理</strong>：在操作數超過 100 次或快取條目超過 1000 時觸發清理</li><li><strong>多遍正規表示式處理</strong>：支援任意巢狀深度的 Markdown 符號剝離</li></ul><div class="tip custom-block"><p class="custom-block-title">快取機制</p><p>快取設計用於最佳化重複內容的寬度計算。例如，當表格中多次出現相同的儲存格文字時，只會計算一次寬度，後續直接從快取讀取。</p></div><h3 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h3><p>本版本不支援以下情境：</p><ul><li><strong>HTML 表格</strong>：僅支援 Markdown 管道表格（Pipe Table）</li><li><strong>多行儲存格</strong>：不支援包含 <code>&lt;br&gt;</code> 標籤的儲存格</li><li><strong>無分隔行表格</strong>：表格必須包含分隔行（<code>|---|</code>）才能被格式化</li><li><strong>依賴要求</strong>：需要 <code>@opencode-ai/plugin</code> &gt;= 0.13.7（使用未公開的 <code>experimental.text.complete</code> 鉤子）</li></ul><div class="info custom-block"><p class="custom-block-title">版本要求</p><p>外掛依賴 OpenCode &gt;= 1.0.137 和 <code>@opencode-ai/plugin</code> &gt;= 0.13.7 才能正常運作。</p></div><hr><h2 id="未來計畫" tabindex="-1">未來計畫 <a class="header-anchor" href="#未來計畫" aria-label="Permalink to &quot;未來計畫&quot;">​</a></h2><p>以下功能計畫在未來的版本中實現：</p><ul><li><strong>配置選項</strong>：支援自訂最小/最大列寬、停用特定功能</li><li><strong>無表頭表格支援</strong>：格式化沒有表頭行的表格</li><li><strong>效能最佳化</strong>：針對超大表格（100+ 行）的效能分析和最佳化</li><li><strong>更多對齊選項</strong>：擴展對齊方式的語法和功能</li></ul><div class="tip custom-block"><p class="custom-block-title">參與貢獻</p><p>如果你有功能建議或想貢獻程式碼，歡迎在 <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提出你的想法。</p></div><hr><h2 id="變更記錄格式說明" tabindex="-1">變更記錄格式說明 <a class="header-anchor" href="#變更記錄格式說明" aria-label="Permalink to &quot;變更記錄格式說明&quot;">​</a></h2><p>本專案的更新日誌遵循 <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> 格式，版本號遵循 <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">語義化版本規範 (Semantic Versioning)</a>。</p><p><strong>版本號格式</strong>：<code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>：不相容的 API 變更</li><li><strong>MINOR</strong>：向後相容的新功能</li><li><strong>PATCH</strong>：向後相容的問題修復</li></ul><p><strong>變更類型</strong>：</p><ul><li><strong>Added</strong>：新增功能</li><li><strong>Changed</strong>：現有功能的變更</li><li><strong>Deprecated</strong>：即將移除的功能</li><li><strong>Removed</strong>：已移除的功能</li><li><strong>Fixed</strong>：問題修復</li><li><strong>Security</strong>：安全相關修復</li></ul><hr><h2 id="建議閱讀順序" tabindex="-1">建議閱讀順序 <a class="header-anchor" href="#建議閱讀順序" aria-label="Permalink to &quot;建議閱讀順序&quot;">​</a></h2><p>如果你是新使用者，建議按以下順序學習：</p><ol><li><a href="./../../start/getting-started/">一分鐘上手：安裝與配置</a> —— 快速上手</li><li><a href="./../../start/features/">功能全覽：自動格式化的魔法</a> —— 了解核心功能</li><li><a href="./../../faq/troubleshooting/">常見問題：表格沒格式化怎麼辦</a> —— 故障排查</li><li><a href="./../../appendix/limitations/">已知限制：外掛的邊界在哪裡</a> —— 了解限制</li></ol>',31)])])}const m=o(a,[["render",i]]);export{h as __pageData,m as default};
